func isZeroPayloadValue(v any) bool {
	switch x := v.(type) {
	case string: return x == ""
	case int: return x == 0
	case int64: return x == 0
	case float64: return x == 0
	case bool: return !x
	case map[string]any: return len(x) == 0
	case []string: return len(x) == 0
	default: return v == nil
	}
}
